class Solution:
    def exist(self, board, word):
        m, n = len(board), len(board[0])
        L = len(word)
        def dfs(i, j, k, used):
            if k == L:
                return True
            if i < 0 or i >= m or j < 0 or j >= n:
                return False
            if (i, j) in used or board[i][j] != word[k]:
                return False
            used.add((i, j))
            for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                if dfs(i + di, j + dj, k + 1, used):
                    used.discard((i, j))
                    return True
            used.discard((i, j))
            return False
        for i in range(m):
            for j in range(n):
                if dfs(i, j, 0, set()):
                    return True
        return False

